// Build follow-up prompt and write to temp file
const job = $('Find Job By Reply').item.json;
const followUpText = $('Execute Workflow Trigger').item.json.text || '';
const prompt = `You are continuing work on the same repository.

Additional instructions from the user:
${followUpText}

Instructions:
- Apply the changes requested above.
- Commit all changes with a descriptive message.
- Do NOT open pull requests — just commit.`;

const fs = require('fs');
const path = `/tmp/prompt-follow-up-${job.id}.txt`;
fs.writeFileSync(path, prompt);
return { prompt_path: path, job_id: job.id };

